import{_ as e,c as p,o as t,a5 as a}from"./chunks/framework.DwbewbAn.js";const X=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/平台/通用组件/DTM/基础/mysql的XA实操.md","filePath":"packages/doc/src/平台/通用组件/DTM/基础/mysql的XA实操.md","lastUpdated":1711551906000}'),o={name:"doc/平台/通用组件/DTM/基础/mysql的XA实操.md"},c=a('<p>1、首先要确保mysql开启XA事务支持</p><p>SHOW VARIABLES LIKE &#39;%XA%&#39;</p><p>​ <img src="https://note.youdao.com/yws/public/resource/dd5e08d9ecdbcf0ed3189e414e751939/xmlnote/1CC334E3C50A49EC9A761BAA14DE9447/30482" alt="0"></p><p>如果innodb_support_xa的值是ON就说明mysql已经开启对XA事务的支持了。</p><p>如果不是就执行：</p><p>SET innodb_support_xa = ON</p><p>2.简单体验一下2PC提交，xid不能重复</p><p>XA start &#39;4fPqCNTYeSG&#39; UPDATE <code>user_account</code> SET <code>balance</code>=balance + 30,<code>update_time</code>=&#39;2021-06-09 11:50:42.438&#39; WHERE user_id = &#39;1&#39; XA end &#39;4fPqCNTYeSG&#39; XA prepare &#39;4fPqCNTYeSG&#39; -- 当所有的参与者完成了prepare，就进入第二阶段 提交 xa commit &#39;4fPqCNTYeSG&#39;</p><p>否则会报：ERROR 1440 (XAE08): XAER_DUPID: The XID already exists</p><p>注意：</p><p>1.在用一个客户端环境下，XA事务和本地(非XA)事务互相排斥，如果已经发布了XA START来开启一个事务，则本地事务不会被启动，知道XA事务被提交或者被回滚为止；相反的，如果已经使用START TRANSACTION启动一个本地事务，则XA语句不能被使用，直到该事务被提交或者回滚为止，而且XA事务仅仅被InnoDB存储引擎支持。</p><p>2.如果XA事务达到PREPARE状态时MySQL服务器宕机，当服务器重启后，服务器会回滚任何未完成的XA事务，即使该事务已经达到了PREPARE状态；如果客户端连接终止，而服务器继续运行，服务器将回滚任何未完成的XA事务，即使该事务已经达到PREPARED状态。</p>',12),s=[c];function A(_,d,r,n,T,i){return t(),p("div",null,s)}const m=e(o,[["render",A]]);export{X as __pageData,m as default};
